src/api/getDashboardStats.ts.content:
import { z } from 'zod';
import { createEndpoint, Resumes, JobApplications, CoverLetters, InterviewSessions, AtsAnalyses } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  authenticated: true,
  inputSchema: z.object({}),
  outputSchema: z.object({
    resumeCount: z.number(),
    avgAtsScore: z.number(),
    applicationCount: z.number(),
    applicationsByStatus: z.array(z.object({ status: z.string(), count: z.number() })),
    coverLetterCount: z.number(),
    interviewCount: z.number(),
    avgInterviewScore: z.number(),
    recentAnalyses: z.array(z.object({ id: z.string(), title: z.string().optional(), matchScore: z.number().optional(), createdAt: z.string().optional() })),
  }),
  execute: async ({ context }) => {
    const userId = context.user.id;
    const [resumes, apps, cls, interviews, analyses] = await Promise.all([
      Resumes.findAll({ filters: { user: userId } }),
      JobApplications.findAll({ filters: { user: userId } }),
      CoverLetters.findAll({ filters: { user: userId } }),
      InterviewSessions.findAll({ filters: { user: userId } }),
      AtsAnalyses.findAll({ filters: { user: userId }, limit: 5 }),
    ]);

    const avgAts = resumes.records.length > 0
      ? resumes.records.reduce((s, r) => s + (r.atsScore || 0), 0) / resumes.records.length
      : 0;

    const statusCounts: Record<string, number> = {};
    apps.records.forEach(a => { const s = a.status || 'Wishlist'; statusCounts[s] = (statusCounts[s] || 0) + 1; });

    const avgInterview = interviews.records.length > 0
      ? interviews.records.reduce((s, r) => s + (r.score || 0), 0) / interviews.records.length
      : 0;

    return {
      resumeCount: resumes.records.length,
      avgAtsScore: Math.round(avgAts),
      applicationCount: apps.records.length,
      applicationsByStatus: Object.entries(statusCounts).map(([status, count]) => ({ status, count })),
      coverLetterCount: cls.records.length,
      interviewCount: interviews.records.length,
      avgInterviewScore: Math.round(avgInterview),
      recentAnalyses: analyses.records.map(a => ({ id: a.id, title: a.title, matchScore: a.matchScore, createdAt: a.createdAt })),
    };
  },
});

src/api/optimizeResumeATS.ts.content:
import { z } from 'zod';
import { createEndpoint, ZitePdf } from 'zite-integrations-backend-sdk';
import { callGeminiJSON } from '../lib/gemini';

export default createEndpoint({
  authenticated: true,
  inputSchema: z.object({
    resumeText: z.string(),
    jobDescription: z.string().optional(),
  }),
  outputSchema: z.object({
    optimizedText: z.string(),
    pdfUrl: z.string(),
    sections: z.object({
      fullName: z.string(),
      title: z.string(),
      email: z.string(),
      phone: z.string(),
      location: z.string(),
      linkedIn: z.string(),
      summary: z.string(),
      experience: z.array(z.object({
        jobTitle: z.string(),
        company: z.string(),
        duration: z.string(),
        bullets: z.array(z.string()),
      })),
      education: z.array(z.object({
        degree: z.string(),
        institution: z.string(),
        year: z.string(),
      })),
      skills: z.array(z.string()),
      certifications: z.array(z.string()),
      projects: z.array(z.object({
        name: z.string(),
        description: z.string(),
      })),
    }),
  }),
  execute: async ({ input }) => {
    const jdCtx = input.jobDescription ? `\nTarget Job Description:\n${input.jobDescription}\n` : '';

    const prompt = `You are a professional resume writer. Take this resume and rewrite it into a HIGHLY PROFESSIONAL, ATS-OPTIMIZED resume.
${jdCtx}
Original Resume:
${input.resumeText}

Rules:
- Use strong action verbs (Led, Engineered, Optimized, Spearheaded, Architected, Delivered)
- Add quantifiable metrics and numbers wherever possible
- Remove personal pronouns
- Use industry-standard section names
- Optimize keywords for ATS
- Keep bullet points concise (1-2 lines each)
- Ensure proper formatting for ATS parsing
- If job description provided, tailor keywords and skills to match
- Extract or infer contact details from the original resume. If not found, use empty strings.

Return JSON:
{
  "fullName": "Full Name",
  "title": "Professional Title",
  "email": "email@example.com",
  "phone": "+1-234-567-8900",
  "location": "City, State",
  "linkedIn": "linkedin.com/in/profile",
  "summary": "3-4 sentence professional summary with keywords",
  "experience": [
    {
      "jobTitle": "Title",
      "company": "Company Name",
      "duration": "Jan 2022 - Present",
      "bullets": ["Achievement-focused bullet with metrics", "Another bullet"]
    }
  ],
  "education": [
    {"degree": "Degree Name", "institution": "University", "year": "2020"}
  ],
  "skills": ["Skill 1", "Skill 2"],
  "certifications": ["Cert 1"],
  "projects": [
    {"name": "Project Name", "description": "Brief description with impact"}
  ]
}`;

    const sections = await callGeminiJSON(prompt, 'You are an elite resume writer who creates ATS-optimized, professional resumes that pass automated screening systems.');

    // Build formatted text version
    const lines: string[] = [];
    lines.push(sections.fullName.toUpperCase());
    lines.push(sections.title);
    lines.push([sections.email, sections.phone, sections.location, sections.linkedIn].filter(Boolean).join(' | '));
    lines.push('');
    if (sections.summary) { lines.push('PROFESSIONAL SUMMARY', sections.summary, ''); }
    if (sections.experience?.length) {
      lines.push('EXPERIENCE');
      sections.experience.forEach((e: any) => {
        lines.push(`${e.jobTitle} — ${e.company}`);
        lines.push(e.duration);
        e.bullets.forEach((b: string) => lines.push(`• ${b}`));
        lines.push('');
      });
    }
    if (sections.education?.length) {
      lines.push('EDUCATION');
      sections.education.forEach((e: any) => lines.push(`${e.degree} — ${e.institution} (${e.year})`));
      lines.push('');
    }
    if (sections.skills?.length) { lines.push('SKILLS', sections.skills.join(' • '), ''); }
    if (sections.certifications?.length) { lines.push('CERTIFICATIONS', ...sections.certifications, ''); }
    if (sections.projects?.length) {
      lines.push('PROJECTS');
      sections.projects.forEach((p: any) => lines.push(`${p.name}: ${p.description}`));
    }
    const optimizedText = lines.join('\n');

    // Generate professional PDF
    const esc = (s: unknown) => String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

    const expHtml = (sections.experience || []).map((e: any) => `
      <div class="exp">
        <div class="exp-header">
          <div><strong>${esc(e.jobTitle)}</strong> — ${esc(e.company)}</div>
          <div class="date">${esc(e.duration)}</div>
        </div>
        <ul>${(e.bullets || []).map((b: string) => `<li>${esc(b)}</li>`).join('')}</ul>
      </div>`).join('');

    const eduHtml = (sections.education || []).map((e: any) =>
      `<div class="edu-item"><strong>${esc(e.degree)}</strong> — ${esc(e.institution)} <span class="date">${esc(e.year)}</span></div>`
    ).join('');

    const skillsHtml = (sections.skills || []).map((s: string) => `<span class="skill">${esc(s)}</span>`).join('');
    const certHtml = (sections.certifications || []).map((c: string) => `<li>${esc(c)}</li>`).join('');
    const projHtml = (sections.projects || []).map((p: any) => `<div class="proj"><strong>${esc(p.name)}</strong> — ${esc(p.description)}</div>`).join('');

    const html = `<!doctype html>
<html><head><meta charset="utf-8"><style>
@page { size: letter; margin: 0.55in 0.65in; }
body { font-family: 'Helvetica Neue', Arial, sans-serif; color: #1a1a1a; font-size: 10pt; line-height: 1.55; margin: 0; }
h1 { font-size: 20pt; margin: 0 0 2px; letter-spacing: 1px; color: #111; text-transform: uppercase; }
.subtitle { font-size: 11pt; color: #333; margin-bottom: 4px; }
.contact { font-size: 8.5pt; color: #555; margin-bottom: 16px; }
h2 { font-size: 10.5pt; text-transform: uppercase; letter-spacing: 1.5px; color: #1a1a1a; border-bottom: 1.5px solid #333; padding-bottom: 3px; margin: 16px 0 8px; }
.exp { margin-bottom: 10px; }
.exp-header { display: flex; justify-content: space-between; align-items: baseline; margin-bottom: 2px; }
.date { color: #555; font-size: 9pt; white-space: nowrap; }
ul { margin: 3px 0 0 0; padding-left: 18px; }
li { margin-bottom: 2px; font-size: 9.5pt; }
.edu-item { margin-bottom: 4px; }
.skills-wrap { display: flex; flex-wrap: wrap; gap: 5px; }
.skill { background: #f3f4f6; padding: 2px 8px; border-radius: 3px; font-size: 8.5pt; }
.proj { margin-bottom: 5px; font-size: 9.5pt; }
p { margin: 0 0 6px; }
</style></head><body>
<h1>${esc(sections.fullName)}</h1>
<div class="subtitle">${esc(sections.title)}</div>
<div class="contact">${[esc(sections.email), esc(sections.phone), esc(sections.location), esc(sections.linkedIn)].filter(Boolean).join(' &nbsp;|&nbsp; ')}</div>
${sections.summary ? `<h2>Professional Summary</h2><p>${esc(sections.summary)}</p>` : ''}
${expHtml ? `<h2>Experience</h2>${expHtml}` : ''}
${eduHtml ? `<h2>Education</h2>${eduHtml}` : ''}
${skillsHtml ? `<h2>Skills</h2><div class="skills-wrap">${skillsHtml}</div>` : ''}
${certHtml ? `<h2>Certifications</h2><ul>${certHtml}</ul>` : ''}
${projHtml ? `<h2>Projects</h2>${projHtml}` : ''}
</body></html>`;

    const { url: pdfUrl } = await ZitePdf.renderHtml({
      html,
      filename: `${sections.fullName.replace(/\s+/g, '_')}_ATS_Resume.pdf`,
    });

    return { optimizedText, pdfUrl, sections };
  },
});

src/pages/LinkedInReview.tsx.content:
import { useState } from 'react';
import { reviewLinkedIn, ReviewLinkedInOutputType } from 'zite-endpoints-sdk';
import { useFeatureAccess } from '@/hooks/useFeatureAccess';
import UpgradeModal from '@/components/UpgradeModal';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Progress } from '@/components/ui/progress';
import { Sparkles, Copy, Linkedin } from 'lucide-react';
import { toast } from 'sonner';

export default function LinkedInReview() {
  const [headline, setHeadline] = useState('');
  const [about, setAbout] = useState('');
  const [experience, setExperience] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ReviewLinkedInOutputType | null>(null);
  const { checkAccess, showUpgrade, closeUpgrade, onUpgraded, usageCount, limit } = useFeatureAccess('linkedin');

  const handleReview = async () => {
    if (!headline && !about && !experience) { toast.error('Please fill in at least one section'); return; }
    const allowed = await checkAccess(true);
    if (!allowed) return;
    setLoading(true);
    try {
      const r = await reviewLinkedIn({ headline: headline || undefined, about: about || undefined, experience: experience || undefined });
      setResult(r);
    } catch { toast.error('Failed to review'); }
    setLoading(false);
  };

  const handleCopy = (text: string) => { navigator.clipboard.writeText(text); toast.success('Copied to clipboard'); };
  const scoreColor = (s: number) => s >= 80 ? 'text-green-500' : s >= 60 ? 'text-yellow-500' : 'text-red-500';

  return (
    <div className="p-6 md:p-8 max-w-4xl space-y-6">
      <UpgradeModal open={showUpgrade} onClose={closeUpgrade} onUpgraded={onUpgraded} featureName="LinkedIn Review" usageCount={usageCount} limit={limit} />
      <div><h1 className="text-2xl font-bold">LinkedIn Profile Review</h1><p className="text-muted-foreground mt-1">Optimize your LinkedIn profile with AI feedback</p></div>

      {!result ? (
        <Card><CardContent className="p-6 space-y-4">
          <div><label className="text-sm font-medium mb-1 block">Headline</label><Textarea rows={2} value={headline} onChange={e => setHeadline(e.target.value)} placeholder="Your current LinkedIn headline..." /></div>
          <div><label className="text-sm font-medium mb-1 block">About</label><Textarea rows={5} value={about} onChange={e => setAbout(e.target.value)} placeholder="Your LinkedIn about section..." /></div>
          <div><label className="text-sm font-medium mb-1 block">Experience Summary</label><Textarea rows={5} value={experience} onChange={e => setExperience(e.target.value)} placeholder="Copy-paste your experience section..." /></div>
          <Button onClick={handleReview} disabled={loading}><Sparkles className="mr-2 h-4 w-4" />{loading ? 'Reviewing...' : 'Review Profile'}</Button>
        </CardContent></Card>
      ) : (
        <div className="space-y-6">
          <Button variant="outline" onClick={() => setResult(null)}>← Review Another</Button>

          <Card><CardContent className="p-6 flex items-center gap-6">
            <div className="h-16 w-16 rounded-full bg-primary/10 flex items-center justify-center"><Linkedin className="h-8 w-8 text-primary" /></div>
            <div><h2 className="text-lg font-bold">Profile Score: <span className={scoreColor(result.overallScore)}>{result.overallScore}/100</span></h2><p className="text-sm text-muted-foreground">See detailed feedback below</p></div>
          </CardContent></Card>

          {result.sections.map(s => (
            <Card key={s.name}>
              <CardHeader><div className="flex items-center justify-between"><CardTitle className="text-base">{s.name}</CardTitle><span className={`font-bold ${scoreColor(s.score)}`}>{s.score}%</span></div><Progress value={s.score} className="h-2 mt-2" /></CardHeader>
              <CardContent className="space-y-4">
                <div className="p-3 rounded-lg bg-muted/50"><p className="text-xs font-medium text-muted-foreground mb-1">Current</p><p className="text-sm">{s.current || 'Not provided'}</p></div>
                <div className="p-3 rounded-lg bg-primary/5 border border-primary/10">
                  <div className="flex items-center justify-between mb-1"><p className="text-xs font-medium text-primary">Improved Version</p><Button variant="ghost" size="sm" onClick={() => handleCopy(s.improved)}><Copy className="h-3 w-3 mr-1" />Copy</Button></div>
                  <p className="text-sm">{s.improved}</p>
                </div>
                <p className="text-xs text-muted-foreground"><strong>Tips:</strong> {s.tips}</p>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
}

src/api/checkFeatureAccess.ts.content:
import { z } from 'zod';
import { createEndpoint, Users, Resumes, AtsAnalyses, CoverLetters, InterviewSessions } from 'zite-integrations-backend-sdk';

const FREE_LIMIT = 2;

type UsageCounts = Record<string, number>;

function parseUsage(raw?: string): UsageCounts {
  if (!raw) return {};
  try { return JSON.parse(raw); } catch { return {}; }
}

export default createEndpoint({
  authenticated: true,
  inputSchema: z.object({
    feature: z.string(),
    increment: z.boolean().optional(),
  }),
  outputSchema: z.object({
    allowed: z.boolean(),
    usageCount: z.number(),
    limit: z.number(),
    isPremium: z.boolean(),
  }),
  execute: async ({ input, context }) => {
    const plan = context.user.plan || 'Free';
    const isPremium = plan === 'Premium' || plan === 'Admin';

    if (isPremium) {
      // Premium users: always allowed, still track usage
      if (input.increment) {
        const usage = parseUsage(context.user.featureUsage);
        usage[input.feature] = (usage[input.feature] || 0) + 1;
        await Users.update({ id: context.user.id, record: { featureUsage: JSON.stringify(usage) } });
      }
      return { allowed: true, usageCount: 0, limit: 999, isPremium: true };
    }

    // For features backed by DB tables, count records
    let count = 0;
    const userId = context.user.id;

    switch (input.feature) {
      case 'resume': {
        const { records } = await Resumes.findAll({ filters: { user: userId }, limit: 10 });
        count = records.length;
        break;
      }
      case 'ats': {
        const { records } = await AtsAnalyses.findAll({ filters: { user: userId }, limit: 10 });
        count = records.length;
        break;
      }
      case 'coverLetter': {
        const { records } = await CoverLetters.findAll({ filters: { user: userId }, limit: 10 });
        count = records.length;
        break;
      }
      case 'interview': {
        const { records } = await InterviewSessions.findAll({ filters: { user: userId }, limit: 10 });
        count = records.length;
        break;
      }
      default: {
        // For features without a table (roadmap, linkedin, projects), use featureUsage JSON
        const usage = parseUsage(context.user.featureUsage);
        count = usage[input.feature] || 0;
        if (input.increment && count < FREE_LIMIT) {
          usage[input.feature] = count + 1;
          await Users.update({ id: context.user.id, record: { featureUsage: JSON.stringify(usage) } });
          count = count + 1;
        }
        break;
      }
    }

    return {
      allowed: count < FREE_LIMIT,
      usageCount: count,
      limit: FREE_LIMIT,
      isPremium: false,
    };
  },
});

