import { z } from 'zod';
import { createEndpoint, JobApplications } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  authenticated: true,
  inputSchema: z.object({
    id: z.string().optional(),
    company: z.string(),
    role: z.string(),
    jobUrl: z.string().optional(),
    status: z.string(),
    salary: z.string().optional(),
    notes: z.string().optional(),
    appliedDate: z.string().optional(),
    reminderDate: z.string().optional(),
  }),
  outputSchema: z.object({ id: z.string(), success: z.boolean() }),
  execute: async ({ input, context }) => {
    const { id, ...data } = input;
    if (id) {
      await JobApplications.update({ id, record: data });
      return { id, success: true };
    }
    const r = await JobApplications.create({ record: { ...data, user: context.user.id } });
    return { id: r.id, success: true };
  },
});

import { useState, useCallback } from 'react';
import { checkFeatureAccess } from 'zite-endpoints-sdk';

export function useFeatureAccess(featureName: string) {
  const [showUpgrade, setShowUpgrade] = useState(false);
  const [usageCount, setUsageCount] = useState(0);
  const [limit, setLimit] = useState(2);
  const [isPremium, setIsPremium] = useState(false);

  const checkAccess = useCallback(async (increment = false): Promise<boolean> => {
    try {
      const result = await checkFeatureAccess({ feature: featureName, increment });
      setUsageCount(result.usageCount);
      setLimit(result.limit);
      setIsPremium(result.isPremium);

      if (!result.allowed && !result.isPremium) {
        setShowUpgrade(true);
        return false;
      }
      return true;
    } catch {
      // On error, allow usage (don't block user due to check failure)
      return true;
    }
  }, [featureName]);

  const closeUpgrade = useCallback(() => setShowUpgrade(false), []);
  const onUpgraded = useCallback(() => {
    setIsPremium(true);
    setShowUpgrade(false);
  }, []);

  return { checkAccess, showUpgrade, closeUpgrade, onUpgraded, usageCount, limit, isPremium };
}

import { z } from 'zod';
import { createEndpoint } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  authenticated: true,
  inputSchema: z.object({}),
  outputSchema: z.object({
    orderId: z.string(),
    amount: z.number(),
    currency: z.string(),
    keyId: z.string(),
    userName: z.string(),
    userEmail: z.string(),
  }),
  execute: async ({ context }) => {
    const keyId = process.env.ZITE_RAZORPAY_KEY_ID;
    const keySecret = process.env.ZITE_RAZORPAY_KEY_SECRET;

    const auth = btoa(`${keyId}:${keySecret}`);

    const res = await fetch('https://api.razorpay.com/v1/orders', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Basic ${auth}`,
      },
      body: JSON.stringify({
        amount: 8900, // ₹89 in paise
        currency: 'INR',
        receipt: `ascend_pro_${context.user.id.slice(0, 8)}_${Date.now()}`,
        notes: {
          userId: context.user.id,
          userEmail: context.user.email,
          plan: 'Premium',
        },
      }),
    });

    if (!res.ok) {
      const errText = await res.text();
      throw new Error(`Razorpay order creation failed: ${errText}`);
    }

    const order = await res.json() as any;

    return {
      orderId: order.id,
      amount: 8900,
      currency: 'INR',
      keyId,
      userName: [context.user.firstName, context.user.lastName].filter(Boolean).join(' ') || 'User',
      userEmail: context.user.email,
    };
  },
});

import { z } from 'zod';
import { createEndpoint, CoverLetters } from 'zite-integrations-backend-sdk';
import { callGemini } from '../lib/gemini';

export default createEndpoint({
  authenticated: true,
  inputSchema: z.object({
    jobTitle: z.string(),
    company: z.string(),
    jobDescription: z.string(),
    resumeText: z.string().optional(),
    tone: z.string().optional(),
  }),
  outputSchema: z.object({ id: z.string(), content: z.string() }),
  execute: async ({ input, context }) => {
    const resumePart = input.resumeText ? `\n\nCandidate Resume:\n${input.resumeText}` : '';
    const prompt = `Write a professional cover letter for the following position:

Job Title: ${input.jobTitle}
Company: ${input.company}
Tone: ${input.tone || 'Professional'}

Job Description:
${input.jobDescription}${resumePart}

Write a compelling, personalized cover letter that:
- Addresses the specific role and company
- Highlights relevant experience and skills
- Shows enthusiasm for the role
- Is concise (3-4 paragraphs)
- Uses a ${input.tone || 'professional'} tone
- Does NOT include placeholder brackets like [Your Name]

Return ONLY the cover letter text, no extra formatting.`;

    const content = await callGemini(prompt, 'You are an expert career coach who writes compelling, personalized cover letters that get interviews.');

    const cl = await CoverLetters.create({
      record: {
        title: `${input.jobTitle} at ${input.company}`,
        user: context.user.id,
        company: input.company,
        jobTitle: input.jobTitle,
        content,
      },
    });

    return { id: cl.id, content };
  },
});

